bool NePyStructPropSet_Transform(const FStructProperty* InStructProp, FNePyStructBase* InSelf, void* InBuffer)
{
	if (FNePyStruct_Transform* PyObj = NePyStructCheck_Transform(InSelf))
	{
		InStructProp->Struct->CopyScriptStruct(InBuffer, PyObj->Value);
		return true;
	}
	return false;
}

FNePyStructBase* NePyStructPropGet_Transform(const FStructProperty* InStructProp, const void* InBuffer)
{
	PyTypeObject* PyType = &FNePyStructType_Transform;
	FNePyStruct_Transform* PyObj = (FNePyStruct_Transform*)PyType->tp_alloc(PyType, 0);
#if NEPY_ENABLE_STRUCT_DEEP_ACCESS
	PyObj->Value = (FTransform*)InBuffer;
	PyObj->SelfCreatedValue = false;
#else
	PyObj->Value = (FTransform*)FMemory::Malloc(sizeof(FTransform), alignof(FTransform));
	NePyBase::EnsureCopyToStructSafely<FTransform>(InStructProp, PyObj->Value);
	InStructProp->Struct->CopyScriptStruct(PyObj->Value, InBuffer);
	PyObj->SelfCreatedValue = true;
#endif
	PyObj->PyOuter = nullptr;
	return PyObj;
}

PyTypeObject* NePyNePyWrappedStructInit_Transform(const UScriptStruct* InScriptStruct, PyTypeObject* InPyBase)
{
	PyTypeObject* NePyStructType = &FNePyStructType_Transform;
	TNePyStructBase<FTransform>::InitTypeCommon(NePyStructType);
	NePyStructType->tp_init = (initproc)&FNePyStruct_Transform_FTransform;
	NePyStructType->tp_methods = FNePyStructType_Transform_methods;
	static PyNumberMethods PyNumber;
	PyNumber.nb_add = (binaryfunc)&FNePyStruct_Transform___add__;
	PyNumber.nb_inplace_add = (binaryfunc)&FNePyStruct_Transform___iadd__;
	PyNumber.nb_multiply = (binaryfunc)&FNePyStruct_Transform___mul__;
	PyNumber.nb_inplace_multiply = (binaryfunc)&FNePyStruct_Transform___imul__;
	NePyStructType->tp_as_number = &PyNumber;
	NePyStructType->tp_base = InPyBase;
	PyType_Ready(NePyStructType);

	if (InScriptStruct)
	{
		FNePyStructTypeInfo TypeInfo = {
			NePyStructType,
			ENePyTypeFlags::StaticPyType,
			(NePyStructPropSet)NePyStructPropSet_Transform,
			(NePyStructPropGet)NePyStructPropGet_Transform,
		};
		FNePyWrapperTypeRegistry::Get().RegisterWrappedStructType(InScriptStruct, TypeInfo);
	}

	return NePyStructType;
}

