FNePyStruct_Transform* NePyStructNew_Transform(const FTransform& InValue)
{
	PyTypeObject* PyType = &FNePyStructType_Transform;
	FNePyStruct_Transform* RetValue = (FNePyStruct_Transform*)PyType->tp_alloc(PyType, 0);
	if (FNePyStruct_Transform::Init(RetValue, nullptr, nullptr) < 0)
	{
		Py_DECREF(RetValue);
		return nullptr;
	}
	new(RetValue->Value) FTransform(InValue);
	return RetValue;
}

FNePyStruct_Transform* NePyStructCheck_Transform(PyObject* InPyObj)
{
	if (InPyObj && PyObject_TypeCheck(InPyObj, &FNePyStructType_Transform))
	{
		return (FNePyStruct_Transform*)InPyObj;
	}
	return nullptr;
}

